import cadquery as cq

# Define unit cube dimensions
unit_size = 1.0

# Create the base structure: a 3x2x3 block with missing cubes
# We'll build it by creating individual cubes and combining them

def create_cube(x, y, z):
    """Create a unit cube at position (x, y, z)"""
    return cq.Workplane().box(unit_size, unit_size, unit_size).translate((x * unit_size, y * unit_size, z * unit_size))

# Build the model by adding cubes where they exist in the image
# Based on the isometric view, we have:
# - Bottom layer (z=0): 3 cubes along x-axis, 2 cubes along y-axis (full 3x2)
# - Middle layer (z=1): 3 cubes along x-axis, 2 cubes along y-axis (full 3x2)  
# - Top layer (z=2): Only 2 cubes along x-axis (missing the first one), 2 cubes along y-axis

cubes = []

# Bottom layer (z=0) - full 3x2 grid
for x in range(3):
    for y in range(2):
        cubes.append(create_cube(x, y, 0))

# Middle layer (z=1) - full 3x2 grid
for x in range(3):
    for y in range(2):
        cubes.append(create_cube(x, y, 1))

# Top layer (z=2) - only 2 cubes (x=1 and x=2), full y-range
for x in [1, 2]:
    for y in range(2):
        cubes.append(create_cube(x, y, 2))

# Combine all cubes into a single solid
result = cq.Workplane().add(cubes[0])
for i in range(1, len(cubes)):
    result = result.union(cubes[i])
